sp_widget.client_script:
api.controller=function() {
    var c = this;

    // Set initial limit to 9 (which equals 3 rows on a standard desktop view)
    c.displayLimit = 9; 

    // Function triggered by the 'Show More' button
    c.showMore = function() {
        // Since we capped our backend at 20 jobs, we can just reveal the rest all at once
        c.displayLimit = c.data.jobs.length; 
    };
};

sp_widget.css:
.aums-job-board {
    padding: 20px;
    font-family: 'Source Sans Pro', Helvetica, Arial, sans-serif;
}

.board-header {
    margin-bottom: 30px;
    text-align: center;
}

.board-header h2 {
    color: #2c3e50;
    font-weight: 600;
}

.subtitle {
    color: #7f8c8d;
    font-size: 16px;
}

.empty-state {
    margin-top: 20px;
    font-size: 16px;
}

/* Responsive Grid for Cards */
.job-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 20px;
}

/* Individual Job Card Styling */
.job-card {
    background: #ffffff;
    border: 1px solid #e0e6ed;
    border-radius: 8px;
    padding: 20px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.job-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 10px 20px rgba(0,0,0,0.08);
    border-color: #b0c4de;
}

.card-top {
    margin-bottom: 15px;
}

.job-title {
    font-size: 18px;
    font-weight: 600;
    color: #2980b9;
    margin: 0 0 8px 0;
    line-height: 1.3;
}

.company {
    font-size: 14px;
    color: #34495e;
    font-weight: 500;
}

.card-middle {
    margin-bottom: 20px;
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.location, .date {
    font-size: 13px;
    color: #95a5a6;
}

.fa {
    margin-right: 5px;
}

/* Apply Button Styling */
.apply-btn {
    width: 100%;
    background-color: #2980b9;
    border: none;
    padding: 10px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    transition: background-color 0.2s;
}

.apply-btn:hover {
    background-color: #1c5980;
}

/* Show More Button Styling */
.show-more-container {
    text-align: center;
    margin-top: 35px;
    padding-bottom: 20px;
}

.show-more-btn {
    padding: 10px 30px;
    font-size: 15px;
    font-weight: 600;
    color: #2980b9;
    background-color: transparent;
    border: 2px solid #2980b9;
    border-radius: 25px;
    transition: all 0.2s ease;
}

.show-more-btn:hover {
    background-color: #2980b9;
    color: #ffffff;
}

.show-more-btn .fa {
    margin-left: 8px;
    margin-right: 0;
}

sp_widget.script:
(function() {
    // Initialize empty array to hold the jobs
    data.jobs = [];
    data.departmentName = "General"; 
    var userDeptId = "";

    // 1. THE FIX: Safely query the sys_user table directly from the Scope
    var currentUser = new GlideRecord('sys_user');
    if (currentUser.get(gs.getUserID())) {
        userDeptId = currentUser.getValue('department'); // Grabs the sys_id
    }

    // 2. Proceed if the user actually has a department assigned
    if (userDeptId) {

        var deptGR = new GlideRecord('cmn_department');
        if (deptGR.get(userDeptId)) {
            data.departmentName = deptGR.getValue('name');
        }

        // 3. Query your custom table for matching jobs
        var jobGR = new GlideRecord('x_595775_automat_0_job_recommendations');
        jobGR.addQuery('u_target_department', userDeptId);
        jobGR.orderByDesc('sys_created_on'); 
        jobGR.setLimit(20); 
        jobGR.query();

        // 4. Push the results into our data object for the HTML template
        while (jobGR.next()) {
            data.jobs.push({
                title: jobGR.getValue('u_job_title'),
                company: jobGR.getValue('u_company'),
                location: jobGR.getValue('u_location'),
                link: jobGR.getValue('u_external_link'),
                posted: jobGR.getDisplayValue('sys_created_on').split(' ')[0] 
            });
        }
    }
})();
